+export async function markWorkspaceDeploymentSucceededIfNotCancelled(
+  db: D1Database,
+  input: {
+    workspaceId: string;
+    deploymentId: string;
+    sourceSnapshotSha256: string;
+    sourceBundleKey: string;
+    deployedUrl: string;
+    providerDeploymentId: string;
+    result: unknown;
+    finishedAt: string;
+  }
+): Promise<boolean> {
+  const updatedAt = new Date().toISOString();
+  const result = await db
+    .prepare(
+      `UPDATE workspace_deployments
+       SET status = 'succeeded',
+           source_snapshot_sha256 = ?,
+           source_bundle_key = ?,
+           deployed_url = ?,
+           provider_deployment_id = ?,
+           result_json = ?,
+           error_code = NULL,
+           error_message = NULL,
+           finished_at = ?,
+           duration_ms = CASE WHEN started_at IS NULL THEN NULL ELSE CAST((julianday(?) - julianday(started_at)) * 86400000 AS INTEGER) END,
+           updated_at = ?
+       WHERE id = ?
+         AND workspace_id = ?
+         AND status = 'running'
+         AND cancel_requested_at IS NULL`
+    )
+    .bind(
+      input.sourceSnapshotSha256,
+      input.sourceBundleKey,
+      input.deployedUrl,
+      input.providerDeploymentId,
+      JSON.stringify(input.result),
+      input.finishedAt,
+      input.finishedAt,
+      updatedAt,
+      input.deploymentId,
+      input.workspaceId
+    )
+    .run();
+
+  return (result.meta?.changes ?? 0) > 0;
+}
